-- Xtradite Digital: Supabase schema + seed data (replaces Wix CMS/Blog/Forms)
-- Run this once in the Supabase SQL Editor for this project.

-- ── Content tables ──────────────────────────────────────────────

create table services (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  slug text not null unique,
  category text,
  icon text,
  summary text,
  hero_subheading text,
  description text,
  sort_order int not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table industries (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  slug text not null unique,
  summary text,
  challenge text,
  solution text,
  outcomes text,
  sort_order int not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table case_studies (
  id uuid primary key default gen_random_uuid(),
  client text not null,
  slug text not null unique,
  industry text,
  headline text,
  challenge text,
  description text,
  metric text,
  sort_order int not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table blog_posts (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  slug text not null unique,
  excerpt text,
  content_text text,
  rich_content jsonb,
  cover_image_url text,
  minutes_to_read int,
  featured boolean not null default false,
  pinned boolean not null default false,
  first_published_at timestamptz not null default now(),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table contact_submissions (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  email text not null,
  company text,
  message text not null,
  created_at timestamptz not null default now()
);

-- ── Row Level Security ──────────────────────────────────────────

alter table services enable row level security;
alter table industries enable row level security;
alter table case_studies enable row level security;
alter table blog_posts enable row level security;
alter table contact_submissions enable row level security;

create policy "Public read services" on services for select to anon using (true);
create policy "Public read industries" on industries for select to anon using (true);
create policy "Public read case_studies" on case_studies for select to anon using (true);
create policy "Public read blog_posts" on blog_posts for select to anon using (true);

-- Contact form: anon can submit, but never read/update/delete other people's submissions.
create policy "Public insert contact_submissions" on contact_submissions for insert to anon with check (true);

-- ── Seed data (migrated from the live Wix site, captured 2026-07-11) ─────
-- Services
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('AI & Automation', 'ai-automation', 'Technology', 'cpu', 'Practical AI and workflow automation that removes manual bottlenecks from operations.', 'Where automation earns its place.', '<p>We identify the manual, repetitive processes actually costing you time and margin — order processing, data reconciliation, reporting — and automate them with tools your team will use. No AI theatre, no unused dashboards.</p>', 1);
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('Digital Strategy', 'digital-strategy', 'Strategy', 'compass', 'A clear, commercially-grounded roadmap for digital-first growth.', 'Strategy that survives contact with delivery.', '<p>We build digital strategy around what your operations can actually execute — sequenced priorities, realistic timelines, and a business case tied to revenue and cost, not slideware.</p>', 2);
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('eCommerce Growth', 'ecommerce-growth', 'Growth', 'trending-up', 'Conversion, retention and fulfilment improvements that compound.', 'Growth built on unit economics, not vanity metrics.', '<p>We work across conversion rate, retention, and fulfilment cost together — because growth that ignores margin isn''t growth. Every recommendation is tied to a number we track post-launch.</p>', 3);
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('Operational Excellence', 'operational-excellence', 'Operations', 'settings', 'Fixing the operational gaps that quietly cap growth.', 'Operations that scale without breaking.', '<p>We map the operational layer — fulfilment, inventory, data flow between systems — and close the gaps that show up as growth ceilings long before anyone traces them back to operations.</p>', 4);
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('Fractional Leadership', 'fractional-leadership', 'Leadership', 'users', 'Senior digital leadership embedded in your team, without the full-time overhead.', 'Leadership when you need it, not a year-long contract.', '<p>A senior operator embedded in your business part-time — running the digital function, mentoring your team, and making the calls a full-time hire would, at a fraction of the cost and commitment.</p>', 5);
insert into services (title, slug, category, icon, summary, hero_subheading, description, sort_order) values ('Project Delivery', 'project-delivery', 'Delivery', 'check-circle', 'Hands-on delivery of the projects strategy decks never finish.', 'We deliver the plan, not just the deck.', '<p>We stay through delivery — implementation, vendor management, testing, launch — because a strategy that never ships isn''t a strategy. We''re judged on what goes live, not what gets presented.</p>', 6);

-- Industries
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('Retail', 'retail', 'Multi-channel retail operations under margin and inventory pressure.', '<p>Retailers juggling in-store, online and marketplace channels end up with fragmented inventory data, inconsistent fulfilment, and no single source of truth for stock or orders.</p>', '<p>We unify fulfilment operations across channels, connect inventory systems, and give ops teams one place to manage stock, orders, and returns.</p>', '<p>Faster fulfilment, fewer stockouts, and a measurable lift in repeat purchase rate within two quarters.</p>', 1);
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('eCommerce', 'ecommerce', 'Digital-native brands scaling past their first operational ceiling.', '<p>Growth outpaces the systems supporting it — checkout conversion stalls, fulfilment costs creep up, and customer acquisition gets more expensive every quarter.</p>', '<p>We rebuild the conversion funnel around real user behaviour, and rework fulfilment economics so growth doesn''t erode margin.</p>', '<p>Higher conversion, lower cost-per-fulfilled-order, and a growth plan the operations team can actually support.</p>', 2);
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('Manufacturing', 'manufacturing', 'Legacy manufacturers digitising operations without disrupting production.', '<p>Decades-old systems and paper-based processes make it hard to get real-time visibility into production, inventory, and order status.</p>', '<p>We digitise the operational layer incrementally — starting where the data gaps hurt most — without forcing a disruptive rip-and-replace.</p>', '<p>Real-time production visibility, fewer manual reconciliation hours, and a foundation for further automation.</p>', 3);
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('Consumer Goods', 'consumer-goods', 'CPG brands managing complex distributor and retail relationships.', '<p>Multiple sales channels and distributor relationships create data silos that make forecasting and inventory planning unreliable.</p>', '<p>We connect distributor, retail, and DTC data into a single operational view, and rebuild forecasting around it.</p>', '<p>More accurate demand forecasting and materially fewer emergency production runs.</p>', 4);
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('Professional Services', 'professional-services', 'Services firms scaling delivery without scaling headcount 1:1.', '<p>Growth in client work outpaces the firm''s ability to hire, and manual processes around scoping, delivery, and reporting eat into margin.</p>', '<p>We streamline delivery operations and automate the reporting and admin work that quietly consumes billable hours.</p>', '<p>Higher utilisation rates and a delivery model that scales without a proportional headcount increase.</p>', 5);
insert into industries (title, slug, summary, challenge, solution, outcomes, sort_order) values ('Startups', 'startups', 'Funded startups that need senior operational judgement fast.', '<p>Early-stage teams need experienced operational and digital leadership but can''t yet justify a full-time senior hire.</p>', '<p>We embed fractional leadership and hands-on delivery to get the operational foundation right before it''s expensive to fix.</p>', '<p>A digital operation built correctly the first time, and a team that knows how to run it after we leave.</p>', 6);

-- Case Studies
insert into case_studies (client, slug, industry, headline, challenge, description, metric, sort_order) values ('Northfield Retail Group', 'northfield-retail-group', 'Retail', 'Rebuilding fulfilment operations for a multi-channel retailer.', 'Fragmented fulfilment data across in-store, online and marketplace channels.', '<p>Northfield Retail Group was running three separate inventory systems across their store, website, and marketplace listings — leading to stockouts, overselling, and manual reconciliation eating hours every week. We unified fulfilment operations onto a single system, connected inventory in real time across channels, and rebuilt their order routing logic. Within two quarters, conversion grew 42% and stockout-related cancellations dropped to near zero.</p>', '+42% Growth', 1);
insert into case_studies (client, slug, industry, headline, challenge, description, metric, sort_order) values ('Kaldura Manufacturing', 'kaldura-manufacturing', 'Manufacturing', 'Digitising production tracking without stopping the production line.', 'Legacy, paper-based production tracking with no real-time visibility.', '<p>Kaldura Manufacturing was tracking production status on paper, reconciled into spreadsheets at the end of each shift — a process prone to error and days behind reality. We digitised production tracking incrementally, floor by floor, without disrupting output. Manual reconciliation hours dropped 31%, and management gained real-time visibility into production status for the first time.</p>', '-31% Manual Hours', 2);
insert into case_studies (client, slug, industry, headline, challenge, description, metric, sort_order) values ('Verlane Marketplace', 'verlane-marketplace', 'eCommerce', 'Rebuilding a marketplace checkout funnel around real buyer behaviour.', 'Rising customer acquisition costs and a checkout funnel losing buyers.', '<p>Verlane Marketplace was acquiring traffic effectively but losing the majority of buyers at checkout. We rebuilt the funnel around session-level behavioural data, simplified checkout to three steps, and restructured shipping pricing. Checkout conversion more than doubled within the first quarter post-launch.</p>', '+2.1x Conversion', 3);

-- Blog posts
insert into blog_posts (title, slug, excerpt, content_text, rich_content, minutes_to_read, featured, pinned, first_published_at) values ('The Real Cost of Fragmented Fulfilment Data', 'the-real-cost-of-fragmented-fulfilment-data', 'When inventory data lives in three different systems, the cost does not show up as a line item. It shows up as overselling, stockout cancellations, and hours of manual reconciliation that nobody is tracking against a budget. Most retailers assume their inventory problem is operational. In reality, it is commercial. Every time your data falls out of sync, it directly impacts revenue, customer trust, and team efficiency. We recently unified fulfilment operations for a multi-channel retailer...', 'When inventory data lives in three different systems, the cost does not show up as a line item. It shows up as overselling, stockout cancellations, and hours of manual reconciliation that nobody is tracking against a budget. Most retailers assume their inventory problem is operational. In reality, it is commercial. Every time your data falls out of sync, it directly impacts revenue, customer trust, and team efficiency. We recently unified fulfilment operations for a multi-channel retailer running separate systems for in-store, online, and marketplace inventory. The result was a 42% lift in conversion. Not because we changed pricing, UX, or marketing, but because we stopped selling stock that did not exist. That is the hidden cost of fragmented inventory systems: you are not just losing time, you are actively suppressing demand. The hidden cost of disconnected inventory When systems are not aligned, the damage spreads across the business in ways that are easy to miss: Lost revenue from overselling, followed by cancellations and refunds. Reduced conversion rates due to poor stock accuracy. Increased customer service load from “where is my order?” queries. Operational drag from manual stock reconciliation. Lower customer lifetime value due to broken trust. According to McKinsey’s supply chain inventory optimisation insights, companies that improve inventory accuracy can reduce stockouts while also lowering inventory holding costs. At the same time, research from IHL’s retail out-of-stocks and overstocks study estimates that global retailers lose hundreds of billions annually due to stockouts and overstocks combined. This is not a niche issue. It is a structural one. Why it happens Most multi-channel retailers did not design their systems to scale together. Instead, they layered them over time: One system for in-store POS. Another for eCommerce. A separate integration for marketplaces like Amazon or eBay. Spreadsheets or manual processes to bridge the gaps. Each system may work independently, but none of them provide a single source of truth. The result is latency. Stock updates lag behind reality. Orders are placed against outdated availability. Teams compensate manually, which introduces even more risk. Three signs your fulfilment data is already costing you If any of these sound familiar, the cost is already there — it is just hidden: Your team reconciles stock manually at the end of each day. Customers occasionally order something that has already sold out elsewhere. Nobody can tell you, in real time, exactly how much of a given SKU you have across all channels combined. These are not edge cases. They are indicators that your inventory system is reactive rather than real-time. And that gap is where revenue leaks. Why fixing it drives conversion Accurate inventory does more than prevent errors. It actively improves performance: Customers are more likely to complete a purchase when availability is reliable. Fewer cancellations mean fewer refunds and less friction. Marketing spend becomes more efficient because traffic is not wasted on unavailable products. Teams spend less time fixing problems and more time scaling operations. Shopify’s guide to omnichannel retail highlights real-time inventory visibility as a key driver of conversion and customer satisfaction. In other words, inventory accuracy is not just an operations metric. It is a growth lever. What changed in our case In the case of the retailer we worked with, the transformation came from unifying inventory into a single, real-time system across all channels. That meant: One source of truth for stock levels. Instant updates across in-store, online, and marketplaces. Removal of manual reconciliation processes. Clear visibility for both operations and commercial teams. The 42% uplift in conversion was not the result of better marketing. It was the removal of friction that should never have been there. The takeaway If inventory accuracy is not something you can measure in real time, it is already costing you. The impact will not show up neatly in a report. It will show up in missed revenue, wasted ad spend, and frustrated customers. And the longer it goes unaddressed, the more it compounds. If you want, I can also make this more Wix-friendly by formatting it with shorter paragraphs and cleaner heading structure for easier pasting.', '{"nodes": [{"type": "PARAGRAPH", "id": "wuhw51551", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "When inventory data lives in three different systems, the cost does not show up as a line item. It shows up as overselling, stockout cancellations, and hours of manual reconciliation that nobody is tracking against a budget.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}, {"type": "PARAGRAPH", "id": "41o991553", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "Most retailers assume their inventory problem is operational. In reality, it is commercial. Every time your data falls out of sync, it directly impacts revenue, customer trust, and team efficiency.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}, {"type": "PARAGRAPH", "id": "t99fj1555", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "We recently unified fulfilment operations for a multi-channel retailer running separate systems for in-store, online, and marketplace inventory. The result was a 42% lift in conversion. Not because we changed pricing, UX, or marketing, but because we stopped selling stock that did not exist.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}, {"type": "PARAGRAPH", "id": "7vltc1557", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "That is the hidden cost of fragmented inventory systems: you are not just losing time, you are actively suppressing demand.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}, {"type": "HEADING", "id": "the-hidden-cost-of-disconnected-inventory", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "The hidden cost of disconnected inventory", "decorations": []}}], "headingData": {"level": 2, "textStyle": {"textAlignment": "AUTO"}}}, {"type": "PARAGRAPH", "id": "8oke71560", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "When systems are not aligned, the damage spreads across the business in ways that are easy to miss:", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}, {"type": "BULLETED_LIST", "id": "gcwfo1562", "nodes": [{"type": "LIST_ITEM", "id": "gnczr1563", "nodes": [{"type": "PARAGRAPH", "id": "nsy6b1564", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "Lost revenue from overselling, followed by cancellations and refunds.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}]}, {"type": "LIST_ITEM", "id": "e8doh1566", "nodes": [{"type": "PARAGRAPH", "id": "x6pcy1567", "nodes": [{"type": "TEXT", "id": "", "nodes": [], "textData": {"text": "Reduced conversion rates due to poor stock accuracy.", "decorations": []}}], "paragraphData": {"textStyle": {"textAlignment": "AUTO"}}}]}, {"type"